// format definition
    final Double cupTrnasRatio = 12.0; // 啤酒品項以1計算，其餘酒類的瓶跟杯數的轉換比率 1:12

    // filter container
    LinkedList<String> filterList = new LinkedList<String>();

    // get date string
    SimpleDateFormat sdf = new SimpleDateFormat("yyyy/MM/dd");
    Calendar queryCal = Calendar.getInstance();
    queryCal.set(Calendar.YEAR, year);
    queryCal.set(Calendar.MONTH, mon - 1);
    queryCal.set(Calendar.WEEK_OF_MONTH, week);

    // fetch fist day of the week
    queryCal.set(Calendar.DAY_OF_WEEK, Calendar.SUNDAY);
    String firstDayString = sdf.format(queryCal.getTime());

    // fetch last day of the week
    queryCal.set(Calendar.DAY_OF_WEEK, Calendar.SATURDAY);
    String lastDayString = sdf.format(queryCal.getTime());

    // filter by time assigned
    filterList.add(REP_DATE + "|" + NUIFilter.OPERAND_GTE + "|" + firstDayString);
    filterList.add(REP_DATE + "|" + NUIFilter.OPERAND_LTE + "|" + lastDayString);

